-full\"><img src=\"https://puleri-starter-wp-dev.localhost/wp-content/themes/twentytwentyfive/assets/images/book-image-landing.webp\" alt=\"\" style=\"aspect-ratio:16/9;object-fit:cover\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"align\":\"full\",\"className\":\"sf-section sf-section\\u002d\\u002dpattern-section-text\",\"layout\":{\"type\":\"constrained\",\"inherit\":false},\"sfSectionPattern\":\"sf-tt5/section-text\"} -->\n<div class=\"wp-block-group alignfull sf-section sf-section--pattern-section-text\"><!-- wp:group {\"align\":\"full\",\"style\":{\"spacing\":{\"padding\":{\"top\":\"var:preset|spacing|lg\",\"right\":\"var:preset|spacing|lg\",\"bottom\":\"var:preset|spacing|lg\",\"left\":\"var:preset|spacing|lg\"}}},\"backgroundColor\":\"accent\",\"layout\":{\"type\":\"constrained\",\"inherit\":false}} -->\n<div class=\"wp-block-group alignfull has-accent-background-color has-background\" style=\"padding-top:var(--wp--preset--spacing--lg);padding-right:var(--wp--preset--spacing--lg);padding-bottom:var(--wp--preset--spacing--lg);padding-left:var(--wp--preset--spacing--lg)\"><!-- wp:group {\"align\":\"wide\",\"style\":{\"spacing\":{\"padding\":{\"top\":\"var:preset|spacing|lg\",\"right\":\"var:preset|spacing|lg\",\"bottom\":\"var:preset|spacing|lg\",\"left\":\"var:preset|spacing|lg\"}}},\"backgroundColor\":\"base\",\"layout\":{\"type\":\"constrained\",\"inherit\":false}} -->\n<div class=\"wp-block-group alignwide has-base-background-color has-background\" style=\"padding-top:var(--wp--preset--spacing--lg);padding-right:var(--wp--preset--spacing--lg);padding-bottom:var(--wp--preset--spacing--lg);padding-left:var(--wp--preset--spacing--lg)\"><!-- wp:heading {\"fontSize\":\"xl\"} -->\n<h2 class=\"wp-block-heading has-xl-font-size\">Un message simple et direct</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"md\"} -->\n<p class=\"has-md-font-size\">Une section de texte pour introduire un sujet, 